+import React, { useState, useEffect } from 'react';
+import api from '../../utils/api';
+import toast from 'react-hot-toast';
+import { FiEdit2, FiTrash2, FiPlus, FiEye, FiToggleLeft, FiToggleRight } from 'react-icons/fi';
+import CashierDetailsModal from './CashierDetailsModal';
+
+const CashierManagement = () => {
+  const [cashiers, setCashiers] = useState([]);
+  const [showModal, setShowModal] = useState(false);
+  const [showDetailsModal, setShowDetailsModal] = useState(false);
+  const [selectedCashier, setSelectedCashier] = useState(null);
+  const [editingCashier, setEditingCashier] = useState(null);
+  const [formData, setFormData] = useState({
+    name: '',
+    email: '',
+    username: '',
+    password: '',
+    phone: '',
+    role: 'cashier',
+    status: 'active'
+  });
+
+  useEffect(() => {
+    fetchCashiers();
+  }, []);
+
+  const fetchCashiers = async () => {
+    try {
+      const res = await api.get('/admin/users');
+      const performanceRes = await api.get('/admin/cashier-performance');
+      const performanceMap = performanceRes.data.reduce((acc, p) => {
+        acc[p.id] = p;
+        return acc;
+      }, {});
+      const combined = res.data.map(c => ({
+        ...c,
+        total_sales: performanceMap[c.id]?.total_sales || 0,
+        transactions: performanceMap[c.id]?.transactions || 0,
+        last_sale: performanceMap[c.id]?.last_sale
+      }));
+      setCashiers(combined);
+    } catch (error) {
+      toast.error('Failed to load cashiers');
+    }
+  };
+
+  const resetForm = () => {
+    setFormData({
+      name: '',
+      email: '',
+      username: '',
+      password: '',
+      phone: '',
+      role: 'cashier',
+      status: 'active'
+    });
+    setEditingCashier(null);
+  };
+
+  const handleInputChange = (e) => {
+    setFormData({ ...formData, [e.target.name]: e.target.value });
+  };
+
+  const handleSubmit = async (e) => {
+    e.preventDefault();
+    try {
+      if (editingCashier) {
+        const data = { ...formData };
+        if (!data.password) delete data.password;
+        await api.put(`/admin/users/${editingCashier.id}`, data);
+        toast.success('Cashier updated');
+      } else {
+        await api.post('/admin/users', formData);
+        toast.success('Cashier added');
+      }
+      setShowModal(false);
+      resetForm();
+      fetchCashiers();
+    } catch (error) {
+      toast.error(editingCashier ? 'Update failed' : 'Add failed');
+    }
+  };
+
+  const handleEdit = (cashier) => {
+    setEditingCashier(cashier);
+    setFormData({
+      name: cashier.name,
+      email: cashier.email,
+      username: cashier.username,
+      password: '',
+      phone: cashier.phone || '',
+      role: cashier.role,
+      status: cashier.status
+    });
+    setShowModal(true);
+  };
+
+  const handleDelete = async (id) => {
+    if (window.confirm('Are you sure you want to delete this cashier?')) {
+      try {
+        await api.delete(`/admin/users/${id}`);
+        toast.success('Cashier deleted');
+        fetchCashiers();
+      } catch (error) {
+        toast.error('Delete failed');
+      }
+    }
+  };
+
+  const toggleStatus = async (cashier) => {
+    const newStatus = cashier.status === 'active' ? 'inactive' : 'active';
+    try {
+      await api.put(`/admin/users/${cashier.id}`, { ...cashier, status: newStatus });
+      toast.success(`Cashier ${newStatus === 'active' ? 'activated' : 'deactivated'}`);
+      fetchCashiers();
+    } catch (error) {
+      toast.error('Status change failed');
+    }
+  };
+
+  const viewDetails = (cashier) => {
+    setSelectedCashier(cashier);
+    setShowDetailsModal(true);
+  };
+
+  return (
+    <div className="space-y-6">
+      <div className="flex justify-between items-center">
+        <h1 className="text-2xl font-bold text-gray-800">Cashier Management</h1>
+        <button onClick={() => { resetForm(); setShowModal(true); }} className="bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded-lg font-medium flex items-center gap-2">
+          <FiPlus /> Add Cashier
+        </button>
+      </div>
+
+      <div className="bg-white rounded-xl shadow-md overflow-hidden">
+        <div className="overflow-x-auto">
+          <table className="min-w-full">
+            <thead className="bg-gray-50">
+              <tr>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Name</th>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Username/Email</th>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Role</th>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Status</th>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Total Sales</th>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Transactions</th>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Last Sale</th>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Actions</th>
+              </tr>
+            </thead>
+            <tbody className="divide-y divide-gray-200">
+              {cashiers.map(c => (
+                <tr key={c.id} className="hover:bg-gray-50">
+                  <td className="px-6 py-4 font-medium">{c.name}</td>
+                  <td className="px-6 py-4">{c.email}<br/><span className="text-xs text-gray-500">{c.username}</span></td>
+                  <td className="px-6 py-4 capitalize">{c.role}</td>
+                  <td className="px-6 py-4">
+                    <span className={`px-2 py-1 rounded-full text-xs font-medium ${c.status === 'active' ? 'bg-green-100 text-green-800' : 'bg-gray-100 text-gray-800'}`}>
+                      {c.status}
+                    </span>
+                  </td>
+                  <td className="px-6 py-4 text-green-600 font-semibold">${c.total_sales?.toFixed(2)}</td>
+                  <td className="px-6 py-4">{c.transactions}</td>
+                  <td className="px-6 py-4">{c.last_sale ? new Date(c.last_sale).toLocaleDateString() : '—'}</td>
+                  <td className="px-6 py-4">
+                    <div className="flex gap-2">
+                      <button onClick={() => toggleStatus(c)} className={`p-1 rounded ${c.status === 'active' ? 'text-green-600 hover:bg-green-50' : 'text-gray-600 hover:bg-gray-100'}`} title={c.status === 'active' ? 'Deactivate' : 'Activate'}>
+                        {c.status === 'active' ? <FiToggleRight size={20} /> : <FiToggleLeft size={20} />}
+                      </button>
+                      <button onClick={() => viewDetails(c)} className="text-blue-600 hover:text-blue-800 p-1 rounded hover:bg-blue-50" title="View Details">
+                        <FiEye size={18} />
+                      </button>
+                      <button onClick={() => handleEdit(c)} className="text-indigo-600 hover:text-indigo-800 p-1 rounded hover:bg-indigo-50" title="Edit">
+                        <FiEdit2 size={18} />
+                      </button>
+                      <button onClick={() => handleDelete(c.id)} className="text-red-600 hover:text-red-800 p-1 rounded hover:bg-red-50" title="Delete">
+                        <FiTrash2 size={18} />
+                      </button>
+                    </div>
+                  </td>
+                </tr>
+              ))}
+            </tbody>
+          </table>
+        </div>
+      </div>
+
+      {/* Modal for Add/Edit Cashier */}
+      {showModal && (
+        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
+          <div className="bg-white rounded-xl max-w-md w-full p-6">
+            <h2 className="text-2xl font-bold mb-4">{editingCashier ? 'Edit Cashier' : 'Add Cashier'}</h2>
+            <form onSubmit={handleSubmit} className="space-y-4">
+              <div><label className="input-label">Full Name *</label><input name="name" value={formData.name} onChange={handleInputChange} className="input-field" required /></div>
+              <div><label className="input-label">Email *</label><input type="email" name="email" value={formData.email} onChange={handleInputChange} className="input-field" required /></div>
+              <div><label className="input-label">Username *</label><input name="username" value={formData.username} onChange={handleInputChange} className="input-field" required dir="ltr" /></div>
+              {!editingCashier && <div><label className="input-label">Password *</label><input type="password" name="password" value={formData.password} onChange={handleInputChange} className="input-field" required /></div>}
+              <div><label className="input-label">Phone</label><input name="phone" value={formData.phone} onChange={handleInputChange} className="input-field" /></div>
+              <div><label className="input-label">Role</label><select name="role" value={formData.role} onChange={handleInputChange} className="input-field"><option value="cashier">Cashier</option><option value="admin">Admin</option></select></div>
+              <div><label className="input-label">Status</label><select name="status" value={formData.status} onChange={handleInputChange} className="input-field"><option value="active">Active</option><option value="inactive">Inactive</option></select></div>
+              <div className="flex gap-3 pt-4">
+                <button type="submit" className="btn-primary flex-1">Save</button>
+                <button type="button" onClick={() => setShowModal(false)} className="btn-outline flex-1">Cancel</button>
+              </div>
+            </form>
+          </div>
+        </div>
+      )}
+
+      {showDetailsModal && selectedCashier && (
+        <CashierDetailsModal cashier={selectedCashier} onClose={() => setShowDetailsModal(false)} />
+      )}
+    </div>
+  );
+};
+
+export default CashierManagement;
